const now = new Date();
const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

// --- Helper: unwrap Bellkeeper {"data": ...} wrapper ---
const unwrap = (nodeName) => {
  try {
    const raw = $(nodeName).first().json;
    return raw.data || raw;
  } catch { return {}; }
};

// --- Service Health ---
const healthData = unwrap('获取服务状态');
const services = healthData.services || {};
const svc = (name) => (services[name]?.status === 'up') ? '\u2705' : (services[name]?.status ? `\u26a0\ufe0f ${services[name].status}` : '\u274c');

// --- Article / Dataset ---
const datasetsRes = $('获取文章总数').first().json;
const datasetsData = datasetsRes.data || datasetsRes;
const totalArticles = datasetsRes.total || 0;
const datasets = datasetsData || [];

// --- Todos ---
const todoRes = $('获取待办事项').first().json;
const todoCount = (todoRes.memos || []).length;

// --- Content collection stats ---
const extLogsData = unwrap('获取RSS采集详情');
const extLogs = extLogsData.items || [];
const extSuccess = extLogs.filter(l => l.status === 'success').length;
const extFailed = extLogs.filter(l => l.status === 'failed').length;

const ingLogsData = unwrap('获取今日采集统计');
const ingLogs = ingLogsData.items || [];
const ingSuccess = ingLogs.filter(l => l.status === 'success').length;
const ingFailed = ingLogs.filter(l => l.status === 'failed' || l.status === 'db_failed').length;

const failedContent = [...extLogs, ...ingLogs]
  .filter(l => l.status === 'failed' || l.status === 'db_failed')
  .slice(0, 10)
  .map(l => `- ${l.summary || ''}`);

// --- Crawl Queue Stats ---
const crawlStatsData = unwrap('获取爬取队列统计');

// --- Dead Jobs (today) ---
const deadJobsRaw = unwrap('获取今日失败任务');
const deadJobs = deadJobsRaw.items || deadJobsRaw || [];
const deadTotal = deadJobsRaw.total || deadJobs.length;

// --- Blocked Jobs (today) ---
const blockedJobsRaw = unwrap('获取今日阻塞任务');
const blockedJobs = blockedJobsRaw.items || blockedJobsRaw || [];
const blockedTotal = blockedJobsRaw.total || blockedJobs.length;

// --- Worker Health ---
const workersRaw = unwrap('获取爬取Worker状态');
const workers = Array.isArray(workersRaw) ? workersRaw : [];

// --- LLM Health ---
const llmHealthRaw = unwrap('获取LLM代理健康');
const llmChannels = Array.isArray(llmHealthRaw) ? llmHealthRaw : [];

// --- Knowledge Index Stats ---
const knowledgeStatsData = unwrap('获取知识库索引统计');

// ===================== BUILD MARKDOWN =====================
let md = `### \ud83d\udcca \u6bcf\u65e5\u77e5\u8bc6\u5e93\u6458\u8981 - ${dateStr}\n\n`;

// --- Service Status ---
md += `#### \ud83d\udce6 \u670d\u52a1\u72b6\u6001\n\n`;
md += `| \u670d\u52a1 | \u72b6\u6001 |\n|------|------|\n`;
md += `| RagFlow | ${svc('ragflow')} |\n`;
md += `| n8n | ${svc('n8n')} |\n`;
md += `| Meilisearch | ${svc('meilisearch')} |\n\n`;

// --- Content Collection ---
md += `#### \ud83d\udce5 \u4eca\u65e5\u5185\u5bb9\u91c7\u96c6\n\n`;
const totalSuccess = extSuccess + ingSuccess;
const totalFailed = extFailed + ingFailed;
if (totalSuccess > 0 || totalFailed > 0) {
  md += `| \u6307\u6807 | \u6570\u91cf |\n|------|------|\n`;
  md += `| \u63d0\u53d6\u6210\u529f | ${extSuccess} \u7bc7 |\n`;
  md += `| \u63d0\u53d6\u5931\u8d25 | ${extFailed} \u7bc7 |\n`;
  md += `| \u5165\u5e93\u6210\u529f | ${ingSuccess} \u7bc7 |\n`;
  md += `| \u5165\u5e93\u5931\u8d25 | ${ingFailed} \u7bc7 |\n\n`;
  if (failedContent.length > 0) {
    md += `**\u5931\u8d25\u8bb0\u5f55:**\n\n`;
    md += failedContent.join('\n') + '\n\n';
  }
} else {
  md += `*\u4eca\u65e5\u65e0\u91c7\u96c6\u8bb0\u5f55*\n\n`;
}

// --- Crawl Queue Overview ---
md += `#### \ud83d\udd77\ufe0f \u722c\u53d6\u961f\u5217\u6982\u89c8\n\n`;
const statusLabels = {
  pending: '\u5f85\u5904\u7406', running: '\u8fd0\u884c\u4e2d', success: '\u6210\u529f',
  retrying: '\u91cd\u8bd5\u4e2d', blocked: '\u5df2\u963b\u585e', dead: '\u5df2\u6b7b\u4ea1',
  skipped: '\u5df2\u8df3\u8fc7', failed: '\u5931\u8d25'
};
const significantStatuses = Object.entries(statusLabels).filter(([key]) => crawlStatsData[key] > 0);
if (significantStatuses.length > 0) {
  md += `| \u72b6\u6001 | \u6570\u91cf |\n|------|------|\n`;
  significantStatuses.forEach(([key, label]) => {
    md += `| ${label} | ${crawlStatsData[key]} |\n`;
  });
  md += '\n';
} else {
  md += `*\u961f\u5217\u7a7a\u95f2*\n\n`;
}

if (crawlStatsData.running > 0) {
  md += `> \u26a0\ufe0f \u6709 ${crawlStatsData.running} \u4e2a\u4efb\u52a1\u5904\u4e8e\u8fd0\u884c\u4e2d\u72b6\u6001\uff0c\u53ef\u80fd\u5361\u4f4f\n\n`;
}

// --- Today's Dead Jobs ---
if (deadJobs.length > 0) {
  md += `#### \ud83d\udc80 \u4eca\u65e5\u5931\u8d25\u4efb\u52a1 (${deadTotal})\n\n`;
  md += `| URL | \u9519\u8bef\u7c7b\u578b | \u9519\u8bef\u4fe1\u606f |\n|-----|---------|--------|\n`;
  deadJobs.slice(0, 15).forEach(j => {
    const shortUrl = (j.url || '').length > 60 ? j.url.substring(0, 57) + '...' : (j.url || '');
    const errType = j.error_type || '';
    const errMsg = (j.error_message || '').length > 50 ? j.error_message.substring(0, 47) + '...' : (j.error_message || '');
    md += `| ${shortUrl} | ${errType} | ${errMsg} |\n`;
  });
  if (deadTotal > 15) {
    md += `\n> ...\u53ca\u5176\u4ed6 ${deadTotal - 15} \u4e2a\n`;
  }
  md += '\n';
}

// --- Today's Blocked Jobs ---
if (blockedJobs.length > 0) {
  md += `#### \ud83d\udeab \u4eca\u65e5\u963b\u585e\u4efb\u52a1 (${blockedTotal})\n\n`;
  md += `| URL | \u963b\u585e\u539f\u56e0 |\u57df\u540d|\n|-----|--------|-----|\n`;
  blockedJobs.slice(0, 15).forEach(j => {
    const shortUrl = (j.url || '').length > 60 ? j.url.substring(0, 57) + '...' : (j.url || '');
    md += `| ${shortUrl} | ${j.block_reason || ''} | ${j.source_domain || ''} |\n`;
  });
  if (blockedTotal > 15) {
    md += `\n> ...\u53ca\u5176\u4ed6 ${blockedTotal - 15} \u4e2a\n`;
  }
  md += '\n';

  // Top blocked domains
  const domainBlockCounts = {};
  blockedJobs.forEach(j => {
    const domain = j.source_domain || 'unknown';
    const reason = j.block_reason || 'unknown';
    const key = `${domain} (${reason})`;
    domainBlockCounts[key] = (domainBlockCounts[key] || 0) + 1;
  });
  const sortedDomains = Object.entries(domainBlockCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5);
  if (sortedDomains.length > 0) {
    md += `**\u963b\u585e\u57df\u540d Top 5:**\n\n`;
    sortedDomains.forEach(([key, count]) => {
      md += `- ${key}: ${count} \u4e2a\n`;
    });
    md += '\n';
  }
}

// --- Worker Health ---
md += `#### \ud83d\udd27 Worker \u901a\u9053\u72b6\u6001\n\n`;
if (workers.length > 0) {
  md += `| \u901a\u9053 | \u7194\u65ad\u5668 | \u8fde\u7eed\u5931\u8d25 | \u5de5\u4eba\u6570 |\n|------|--------|----------|--------|\n`;
  workers.forEach(w => {
    const breakerIcon = w.breaker_state === 'closed' ? '\u2705' :
                        w.breaker_state === 'open' ? '\ud83d\udd34' : '\ud83d\udfe1';
    md += `| ${w.channel || ''} | ${breakerIcon} ${w.breaker_state || ''} | ${w.consecutive_fail || 0} | ${w.worker_count || 0} |\n`;
  });
  md += '\n';
} else {
  md += `*\u65e0 Worker \u6570\u636e*\n\n`;
}

// --- LLM Proxy Health ---
if (llmChannels.length > 0) {
  md += `#### \ud83e\udd16 LLM \u4ee3\u7406\u5065\u5eb7\n\n`;
  const healthyCount = llmChannels.filter(c => c.health === 'healthy').length;
  md += `- \u5065\u5eb7: ${healthyCount}/${llmChannels.length} \u4e2a\u901a\u9053\n`;
  const unhealthy = llmChannels.filter(c => c.health !== 'healthy');
  if (unhealthy.length > 0) {
    md += `- \u5f02\u5e38\u901a\u9053: ${unhealthy.map(c => c.name || c.channel || 'unknown').join(', ')}\n`;
  }
  md += '\n';
}

// --- Knowledge Base Stats ---
md += `#### \ud83d\udcda \u77e5\u8bc6\u5e93\u7edf\u8ba1\n\n`;
md += `- **\u6587\u7ae0\u603b\u6570**: ${totalArticles} \u7bc7\n`;
if (knowledgeStatsData.total_files !== undefined) {
  md += `- **\u7d22\u5f15\u6587\u4ef6\u6570**: ${knowledgeStatsData.total_files}\n`;
}
if (knowledgeStatsData.total_chunks !== undefined) {
  md += `- **\u7d22\u5f15\u5206\u5757\u6570**: ${knowledgeStatsData.total_chunks}\n`;
}
if (knowledgeStatsData.skipped_files !== undefined) {
  md += `- **\u8df3\u8fc7\u6587\u4ef6\u6570**: ${knowledgeStatsData.skipped_files}\n`;
}
md += '\n';

// --- Dataset lines ---
const datasetLines = datasets.map(d => `  - ${d.display_name || d.name}: ${(d.tags?.length || 0)} \u6807\u7b7e`);
if (datasetLines.length > 0) {
  md += `| \u6570\u636e\u96c6 | \u6807\u7b7e\u6570 |\n|---------|--------|\n`;
  md += datasetLines.map(l => l.replace(/^  - /, '| ').replace(': ', '| ')).join(' \u6807\u7b7e\n') + ' \u6807\u7b7e\n\n';
}

// --- Todos ---
md += `#### \ud83d\udcdd \u5f85\u529e\u4e8b\u9879\n\n`;
md += `- \u672a\u5b8c\u6210: ${todoCount} \u9879`;

return [{ json: { room: 'daily', markdown: md, date: dateStr } }];
